class Solution:
    def intervalIntersection(self, firstList, secondList):
        res = []
        for a0, a1 in firstList:
            for b0, b1 in secondList:
                lo = max(a0, b0)
                hi = min(a1, b1)
                if lo <= hi:
                    res.append([lo, hi])
        res.sort()
        return res

